// Value Object: immutable, self-validating, equality by value
export class Money {
  private constructor(
    public readonly amount: bigint,   // minor units (cents) — never floats
    public readonly currency: string
  ) {}

  static of(amount: bigint, currency: string): Money {
    if (amount < 0n) throw new Error('Money cannot be negative');
    if (!/^[A-Z]{3}$/.test(currency)) throw new Error('Invalid currency');
    return new Money(amount, currency);
  }

  add(other: Money): Money {
    if (other.currency !== this.currency)
      throw new Error('Currency mismatch');
    return new Money(this.amount + other.amount, this.currency);
  }

  equals(other: Money): boolean {
    return this.amount === other.amount && this.currency === other.currency;
  }
}

// One repository per aggregate root. Deals in whole aggregates only.
export interface OrderRepository {
  findById(id: OrderId): Promise<Order | null>;
  save(order: Order): Promise<void>;   // persists the whole aggregate atomically
  nextIdentity(): OrderId;             // ids are minted by the domain, not the DB
}

// Notice what is NOT here: no findOrderLineById, no updateOrderStatus.
// You load the Order, mutate it through its root, and save the Order.

// BEFORE: one god-aggregate — every write locks the whole graph
class Customer {
  profile: Profile;
  subscriptions: Subscription[];   // could be hundreds
  invoices: Invoice[];             // could be thousands
  paymentMethods: PaymentMethod[];
}

// AFTER: separate aggregates, referenced by identity
class Customer { id: CustomerId; profile: Profile; }
class Subscription { id: SubscriptionId; customerId: CustomerId; /* ... */ }
class Invoice { id: InvoiceId; customerId: CustomerId; lines: InvoiceLine[]; }
// Appending an invoice now locks ONE Invoice, not the whole customer.

// ACL: a legacy ERP returns a flat, cryptic payload.
// The translator converts it into our domain's value objects.
class ErpCustomerTranslator {
  toDomain(raw: ErpCustomerRecord): Customer {
    return Customer.rehydrate({
      id: new CustomerId(raw.CUST_NO.trim()),
      tier: this.mapTier(raw.PRC_GRP),            // 'A1' -> Tier.Gold
      creditLimit: Money.of(BigInt(raw.CR_LMT_C), raw.CUR_CD),
    });
  }
  private mapTier(code: string): Tier {
    const m: Record<string, Tier> = { A1: Tier.Gold, B2: Tier.Silver };
    return m[code] ?? Tier.Standard;   // fail soft, never leak 'A1' inward
  }
}

