type OrderStatus = 'DRAFT' | 'PLACED';

class Money {
  private constructor(readonly amount: bigint, readonly currency: string) {}
  static of(amount: bigint, currency: string): Money {
    if (amount < 0n) throw new Error('Money cannot be negative');
    if (!/^[A-Z]{3}$/.test(currency)) throw new Error('Bad currency');
    return new Money(amount, currency);
  }
  static zero(currency: string) { return new Money(0n, currency); }
  add(o: Money): Money {
    if (o.currency !== this.currency) throw new Error('Currency mismatch');
    return new Money(this.amount + o.amount, this.currency);
  }
  multiply(q: number): Money {
    return new Money(this.amount * BigInt(q), this.currency);
  }
  equals(o: Money) { return this.amount === o.amount && this.currency === o.currency; }
}

// Child entity — only the Order root may construct/mutate it.
class OrderLine {
  constructor(
    readonly sku: string,
    readonly unitPrice: Money,
    readonly quantity: number
  ) {
    if (quantity < 1) throw new Error('Quantity must be >= 1');
  }
  subtotal(): Money { return this.unitPrice.multiply(this.quantity); }
}

class OrderPlaced {
  readonly occurredAt = new Date();
  constructor(readonly orderId: string, readonly total: Money) {}
}

class Order {
  private status: OrderStatus = 'DRAFT';
  private lines: OrderLine[] = [];
  private events: object[] = [];

  constructor(
    readonly id: string,
    readonly customerId: string,
    readonly currency: string
  ) {}

  private assertDraft() {
    if (this.status !== 'DRAFT')
      throw new Error('Order is immutable once placed');
  }

  addLine(sku: string, unitPrice: Money, quantity: number): void {
    this.assertDraft();
    if (unitPrice.currency !== this.currency)
      throw new Error('Line currency must match order currency');
    this.lines.push(new OrderLine(sku, unitPrice, quantity));
  }

  removeLine(sku: string): void {
    this.assertDraft();
    this.lines = this.lines.filter(l => l.sku !== sku);
  }

  // Invariant (4): total is always derived, never stored mutably.
  total(): Money {
    return this.lines.reduce(
      (sum, l) => sum.add(l.subtotal()),
      Money.zero(this.currency)
    );
  }

  place(): void {
    this.assertDraft();
    if (this.lines.length === 0)
      throw new Error('Cannot place an order with no lines');
    this.status = 'PLACED';
    this.events.push(new OrderPlaced(this.id, this.total()));
  }

  pullEvents(): object[] {
    const e = this.events; this.events = []; return e;
  }
}

interface DomainEventHandler { handle(event: object): Promise<void>; }

class EventDispatcher {
  private handlers = new Map<string, DomainEventHandler[]>();
  register(eventName: string, h: DomainEventHandler) {
    const list = this.handlers.get(eventName) ?? [];
    list.push(h);
    this.handlers.set(eventName, list);
  }
  async dispatch(events: object[]): Promise<void> {
    for (const e of events) {
      const name = e.constructor.name;
      for (const h of this.handlers.get(name) ?? []) {
        await h.handle(e);
      }
    }
  }
}

class PlaceOrderService {
  constructor(
    private readonly orders: OrderRepository,
    private readonly dispatcher: EventDispatcher
  ) {}

  async placeOrder(orderId: string): Promise<void> {
    const order = await this.orders.findById(orderId);
    if (!order) throw new Error('Order not found');

    order.place();                 // mutate aggregate, raises OrderPlaced

    await this.orders.save(order); // TX commits HERE — durable first

    // Only now is it safe to react. Pull events AFTER commit.
    await this.dispatcher.dispatch(order.pullEvents());
  }
}

// Production-grade: avoid the dual-write gap with an outbox.
// In the SAME transaction as save(order), insert event rows into an
// 'outbox' table. A separate relay polls the outbox and publishes,
// marking rows sent. Commit atomicity guarantees no lost or phantom
// events even if the app crashes right after commit.
interface OrderRepository {
  findById(id: string): Promise<Order | null>;
  save(order: Order): Promise<void>;
}
